mapper.update:
UPDATE event.events
SET  title             = #{title}
    ,description       = COALESCE(#{description}, #{content})
    ,event_type        = COALESCE(NULLIF(#{eventType}, ''), event_type)
    ,is_paid           = COALESCE(#{isPaid}, is_paid)
    ,file_seq          = #{fileSeq}
    ,attachment_file_seq = #{attachmentFileSeq}
    ,start_at          = #{eventStartDt}
    ,end_at            = #{eventEndDt}
    ,registration_start_at = #{registrationStartDt}
    ,registration_end_at   = #{registrationEndDt}
    ,venue_name        = #{location}
    ,max_participants  = #{maxParticipants}
    ,organization_seq  = #{organizationSeq}
    ,registration_type = COALESCE(NULLIF(#{registrationType,jdbcType=VARCHAR}, ''), registration_type)
    ,registration_url  = #{registrationUrl,jdbcType=VARCHAR}
    ,status            = #{status}
    ,updated_by        = #{uptUserSeq}
    ,updated_at        = CURRENT_TIMESTAMP
WHERE event_seq = #{eventSeq}
  AND deleted_at IS NULL

UPDATE event.event_pricing ep
SET  price_type      = CASE
                        WHEN EXISTS (
                            SELECT 1
                            FROM event.payments p
                            WHERE p.event_pricing_seq = ep.event_pricing_seq
                            LIMIT 1
                        )
                        THEN ep.price_type
                        ELSE #{pricing.priceType}
                       END
    ,price_name      = #{pricing.priceName}
    ,currency_code   = #{pricing.currencyCode}
    ,amount          = #{pricing.amount}
    ,sales_start_at  = #{pricing.salesStartAt,jdbcType=TIMESTAMP}
    ,sales_end_at    = #{pricing.salesEndAt,jdbcType=TIMESTAMP}
    ,use_yn          = COALESCE(NULLIF(#{pricing.useYn}, ''), 'Y')
    ,sort_seq        = #{pricing.sortSeq}
    ,updated_by      = #{userSeq}
    ,updated_at      = CURRENT_TIMESTAMP
WHERE ep.event_pricing_seq = #{pricing.eventPricingSeq}
  AND ep.event_seq = #{pricing.eventSeq}
  AND ep.deleted_at IS NULL

UPDATE event.event_discount_codes
SET  discount_code         = CASE
                              WHEN EXISTS (
                                  SELECT 1
                                  FROM event.payments p
                                  WHERE p.discount_code_seq = event.event_discount_codes.discount_code_seq
                              )
                              THEN discount_code
                              ELSE #{discountCode.discountCode}
                              END
    ,discount_type         = #{discountCode.discountType}
    ,discount_value        = #{discountCode.discountValue}
    ,currency_code         = #{discountCode.currencyCode,jdbcType=VARCHAR}
    ,applies_to_price_type = #{discountCode.appliesToPriceType,jdbcType=VARCHAR}
    ,usage_limit           = #{discountCode.usageLimit,jdbcType=INTEGER}
    ,valid_from_at         = #{discountCode.validFromAt,jdbcType=TIMESTAMP}
    ,valid_to_at           = #{discountCode.validToAt,jdbcType=TIMESTAMP}
    ,use_yn                = COALESCE(NULLIF(#{discountCode.useYn}, ''), 'Y')
    ,sort_seq              = #{discountCode.sortSeq}
    ,updated_by            = #{userSeq}
    ,updated_at            = CURRENT_TIMESTAMP
WHERE discount_code_seq = #{discountCode.discountCodeSeq}
  AND event_seq = #{discountCode.eventSeq}
  AND deleted_at IS NULL

UPDATE event.events
SET  status     = #{status}
    ,rejection_reason = #{rejectionReason,jdbcType=VARCHAR}
    ,updated_by = #{updatedBy}
    ,updated_at = CURRENT_TIMESTAMP
WHERE event_seq = #{eventSeq}
  AND deleted_at IS NULL

UPDATE event.events
SET  status     = #{closedStatus}
    ,updated_at = CURRENT_TIMESTAMP
WHERE deleted_at IS NULL
  AND end_at < CURRENT_TIMESTAMP
  AND status != #{closedStatus}

  AND status IN

      #{status}
